import React, { useEffect } from 'react';
import { Linking, Alert } from 'react-native';
import { useNavigation } from '@react-navigation/native';

const DeepLinkHandler = ({ children }) => {
  const navigation = useNavigation();

  const handleDeepLink = (url) => {
    if (!url) return;

    const scheme = 'myapp';
    if (!url.startsWith(`${scheme}://`)) {
      return; // Not our app's deep link
    }

    const path = url.replace(`${scheme}://`, '');
    const [screen, param] = path.split('/');

    switch (screen) {
      case 'profile':
        if (param) {
          navigation.navigate('ProfileScreen', { userId: param });
        } else {
          navigation.navigate('ProfileScreen');
        }
        break;
      case 'payment':
        if (param === 'confirm') {
          navigation.navigate('PaymentConfirmationScreen');
        } else {
          // Handle other payment related paths or default to payment screen
          navigation.navigate('PaymentScreen');
        }
        break;
      case 'settings':
        navigation.navigate('SettingsScreen');
        break;
      default:
        // Optionally navigate to a default screen or show an error
        Alert.alert('Unknown Deep Link', `Could not handle deep link: ${url}`);
        break;
    }
  };

  useEffect(() => {
    // 1. Handle initial deep link when the app is launched from a link
    Linking.getInitialURL().then((url) => {
      if (url) {
        handleDeepLink(url);
      }
    });

    // 2. Handle deep links when the app is already running and a new link is opened
    const subscription = Linking.addEventListener('url', ({ url }) => {
      handleDeepLink(url);
    });

    return () => {
      // Clean up the event listener when the component unmounts
      subscription.remove();
    };
  }, []); // Empty dependency array ensures this effect runs only once on mount

  return children; // Render child components normally
};

export default DeepLinkHandler;

